const express = require('express');
const morgan = require('morgan');
const winston = require('winston');
const path = require('path');

const app = express();
app.use(express.json());
app.use(express.urlencoded({ extended: true }));

// --- Log Injection Prevention Utilities ---

/**
 * Sanitizes user-provided input before writing to logs.
 * Prevents log injection by removing/replacing control characters,
 * newlines, and other dangerous sequences.
 */
function sanitizeLogInput(input) {
    if (input === null || input === undefined) {
        return '';
    }

    if (typeof input !== 'string') {
        input = String(input);
    }

    // Remove newlines, carriage returns, tabs, and other control characters
    // that could be used for log injection / log forging
    let sanitized = input
        .replace(/[\r\n]/g, '_')        // Replace newlines/carriage returns
        .replace(/[\t]/g, ' ')          // Replace tabs with spaces
        .replace(/[\x00-\x1F\x7F]/g, '') // Remove other control characters
        .replace(/\x1b\[[0-9;]*m/g, ''); // Remove ANSI escape codes

    // Limit length to prevent log flooding
    const MAX_LOG_FIELD_LENGTH = 500;
    if (sanitized.length > MAX_LOG_FIELD_LENGTH) {
        sanitized = sanitized.substring(0, MAX_LOG_FIELD_LENGTH) + '...[TRUNCATED]';
    }

    return sanitized;
}

/**
 * Sanitizes an object's string values recursively for safe logging.
 */
function sanitizeObjectForLog(obj, depth = 0) {
    if (depth > 5) return '[MAX_DEPTH]';
    if (obj === null || obj === undefined) return obj;
    if (typeof obj === 'string') return sanitizeLogInput(obj);
    if (typeof obj === 'number' || typeof obj === 'boolean') return obj;

    if (Array.isArray(obj)) {
        return obj.map(item => sanitizeObjectForLog(item, depth + 1));
    }

    if (typeof obj === 'object') {
        const sanitized = {};
        for (const [key, value] of Object.entries(obj)) {
            const sanitizedKey = sanitizeLogInput(key);
            sanitized[sanitizedKey] = sanitizeObjectForLog(value, depth + 1);
        }
        return sanitized;
    }

    return String(obj);
}

// --- Winston Logger Setup ---

const logger = winston.createLogger({
    level: 'info',
    format: winston.format.combine(
        winston.format.timestamp({ format: 'YYYY-MM-DD HH:mm:ss' }),
        winston.format.printf(({ timestamp, level, message, ...meta }) => {
            const metaStr = Object.keys(meta).length ? ` ${JSON.stringify(meta)}` : '';
            return `${timestamp} [${level.toUpperCase()}]: ${message}${metaStr}`;
        })
    ),
    transports: [
        new winston.transports.File({
            filename: path.join(__dirname, 'logs', 'audit.log'),
            maxsize: 10 * 1024 * 1024, // 10MB
            maxFiles: 5
        }),
        new winston.transports.File({
            filename: path.join(__dirname, 'logs', 'error.log'),
            level: 'error',
            maxsize: 10 * 1024 * 1024,
            maxFiles: 5
        }),
        new winston.transports.Console({
            format: winston.format.combine(
                winston.format.colorize(),
                winston.format.simple()
            )
        })
    ]
});

// --- Morgan Setup with Sanitization ---

// Custom morgan token for sanitized remote user
morgan.token('sanitized-remote-user', (req) => {
    return sanitizeLogInput(req.headers['x-remote-user'] || req.user?.username || 'anonymous');
});

// Custom morgan token for sanitized user-agent
morgan.token('sanitized-user-agent', (req) => {
    return sanitizeLogInput(req.headers['user-agent'] || '');
});

// Custom morgan token for sanitized referrer
morgan.token('sanitized-referrer', (req) => {
    return sanitizeLogInput(req.headers['referer'] || req.headers['referrer'] || '');
});

// Custom morgan token for sanitized URL
morgan.token('sanitized-url', (req) => {
    return sanitizeLogInput(req.originalUrl || req.url);
});

// Custom morgan token for custom headers (sanitized)
morgan.token('custom-header', (req) => {
    return sanitizeLogInput(req.headers['x-custom-header'] || '');
});

// Use morgan with sanitized tokens - write to winston stream
const morganStream = {
    write: (message) => {
        // message from morgan is already sanitized via custom tokens
        logger.info(message.trim());
    }
};

app.use(morgan(
    ':remote-addr - :sanitized-remote-user [:date[clf]] ":method :sanitized-url HTTP/:http-version" :status :res[content-length] ":sanitized-referrer" ":sanitized-user-agent" custom-header=":custom-header"',
    { stream: morganStream }
));

// --- Audit Logging Middleware ---

function auditLog(action) {
    return (req, res, next) => {
        const auditEntry = {
            action: sanitizeLogInput(action),
            ip: sanitizeLogInput(req.ip || req.connection?.remoteAddress || ''),
            username: sanitizeLogInput(req.body?.username || req.headers['x-username'] || 'anonymous'),
            method: sanitizeLogInput(req.method),
            path: sanitizeLogInput(req.originalUrl),
            userAgent: sanitizeLogInput(req.headers['user-agent'] || ''),
            customHeaders: {
                'x-request-id': sanitizeLogInput(req.headers['x-request-id'] || ''),
                'x-correlation-id': sanitizeLogInput(req.headers['x-correlation-id'] || ''),
                'x-custom-header': sanitizeLogInput(req.headers['x-custom-header'] || '')
            },
            timestamp: new Date().toISOString()
        };

        // Log sanitized body data if present (excluding sensitive fields)
        if (req.body && Object.keys(req.body).length > 0) {
            const safeBody = { ...req.body };
            // Remove sensitive fields before logging
            delete safeBody.password;
            delete safeBody.token;
            delete safeBody.secret;
            delete safeBody.creditCard;
            delete safeBody.ssn;
            auditEntry.requestBody = sanitizeObjectForLog(safeBody);
        }

        logger.info('AUDIT', auditEntry);
        next();
    };
}

